  "objectives": [
    "比较 AWS 服务之间的存储成本",
    "评估存储选择的成本影响",
    "应用成本优化策略"
  ],
  "questionProse": [
    "存储 1PB 数据，其中 20% 每天访问，30% 每月访问，50% 每年访问，最具成本效益的方法是什么？"
  ],
  "hintsProse": [],
  "explanationProse": [
    "最佳存储策略：\n    - 20% 使用 S3 Standard 用于每日访问\n    - 30% 使用 S3 Standard-IA 用于每月访问\n    - 50% 使用 Glacier 用于每年访问\n\n    这种方法在保持适当访问模式的同时优化了成本。\n\n    成本考虑因素：\n    - 每 GB 的存储定价\n    - 检索成本\n    - 访问模式\n    - 转换成本"
  ]
}
